(function(){var loadHandler=window['sl_{AE632556-9407-49E6-A743-6210EE80EB10}'];loadHandler&&loadHandler(35, '<div id="spr0_157c06d6"><div id="spr1_157c06d6" class="kern slide"><img id="img2_157c06d6" src="data:image/jpeg;base64," width="1200px" height="672px" alt="" style="left:0px;top:0px;"/></div><div id="spr2_157c06d6" class="kern slide"><div id="spr3_157c06d6" style="left:813.517px;top:160.577px;"><img id="img0_157c06d6" src="data:image/png;base64," width="394.727" height="644.69" alt="" style="left:-22.343px;top:-53.427px;"/></div><div id="spr4_157c06d6" style="left:34.344px;top:42.279px;"><div id="svg7_157c06d6" style="left:-6.75px;top:-4.092px;"><svg width="741" height="596" viewBox="-6.75 -6.75 741 596"><g fill="none"><g transform="translate(6.75,6.75)"><path fill="#ffffff" d="M6.299,0 H707.459 C710.937,0 713.757,2.82 713.757,6.299 V562.328 C713.757,563.998 713.094,565.6 711.913,566.782 C710.731,567.963 709.129,568.627 707.459,568.627 H6.299 C2.82,568.627 0,565.806 0,562.328 V6.299 C0,2.82 2.82,0 6.299,0 Z" fill-rule="evenodd"/></g><g transform="translate(6.75,6.75)"><path stroke="#bdacdb" stroke-width="13.5" stroke-linecap="round" stroke-linejoin="round" d="M6.299,0 H707.459 C710.937,0 713.757,2.82 713.757,6.299 V562.328 C713.757,563.998 713.094,565.6 711.913,566.782 C710.731,567.963 709.129,568.627 707.459,568.627 H6.299 C2.82,568.627 0,565.806 0,562.328 V6.299 C0,2.82 2.82,0 6.299,0 Z"/></g></g></svg></div><div id="svg8_157c06d6" style="left:6.75px;"><svg width="714" height="579" viewBox="0 0 714 579"><path fill="none" d="M0,0 h713.757 v578.035 h-713.757 Z"/></svg></div></div><div id="spr5_157c06d6" style="left:69.936px;top:77.868px;"><div style="width:0px;"><span id="txt0_157c06d6" class="nokern" data-width="302.557129" style="top:7.196px;">Пару дней назад я и Кеми…</span></div></div><div id="spr6_157c06d6" style="left:69.936px;top:117.275px;"><div style="width:0px;"><span id="txt1_157c06d6" class="nokern" data-width="639.111938" style="top:13.404px;">Мы проверяли орбитальную станцию «Маяк». Кеми поручили сопроводить меня</span></div><div style="width:0px;"><span id="txt2_157c06d6" class="nokern" data-width="471.535126" style="top:41.044px;">к смотровой палубе. Это наш первый совместный переход.</span></div><div style="width:0px;"><span id="txt3_157c06d6" class="nokern" data-width="628.791809" style="top:79.916px;">Маршрут занимает около 20 минут. Он включает лестницу из восьми ступеней,</span></div><div style="width:0px;"><span id="txt4_157c06d6" class="nokern" data-width="634.049072" style="top:103.824px;">узкий проход между опорами вентиляции, участок с кабель-каналами на полу и</span></div><div style="width:0px;"><span id="txt5_157c06d6" class="nokern" data-width="291.135071" style="top:127.714px;">крутой поворот у шлюзового отсека.</span></div><div style="width:0px;"><span id="txt6_157c06d6" class="nokern" data-width="618.431152" style="top:166.586px;">Когда мы подошли к лестнице, Кеми на ходу бросил: «Сейчас будет лестница.</span></div><div style="width:0px;"><span id="txt7_157c06d6" class="nokern" data-width="613.983887" style="top:190.494px;">Осторожно!» — и начал подниматься в своём темпе. Я замедлился, выставил</span></div><div style="width:0px;"><span id="txt8_157c06d6" class="nokern" data-width="618.090942" style="top:214.384px;">трость, но не успел вовремя нащупать первую ступень. Сверху Кеми добавил:</span></div><div style="width:0px;"><span id="txt9_157c06d6" class="nokern" data-width="565.153564" style="top:238.274px;">«Вот мы у лестницы, тут восемь ступеней. Поднимайся!». Я растерянно</span></div><div style="width:0px;"><span id="txt10_157c06d6" class="nokern" data-width="444.009308" style="top:262.164px;">пробормотал: «Далеко...» — и начал осторожно подъём.</span></div><div style="width:0px;"><span id="txt11_157c06d6" class="nokern" data-width="631.189575" style="top:301.036px;">Когда подошли к кабель-каналам, Кеми предупредил: «Теперь идём прямо. Тут</span></div><div style="width:0px;"><span id="txt12_157c06d6" class="nokern" data-width="602.918518" style="top:324.944px;">кабели под ногами, но они в защитных кожухах. Ты справишься». Он пошёл</span></div><div style="width:0px;"><span id="txt13_157c06d6" class="nokern" data-width="617.847900" style="top:348.834px;">дальше в своём темпе, не оглядываясь. Я зацепился тростью за край кабель-</span></div><div style="width:0px;"><span id="txt14_157c06d6" class="nokern" data-width="609.188354" style="top:372.724px;">канала и чуть не упал. «Ой... благодарю тебя», — произнёс я чуть смущённо и</span></div><div style="width:0px;"><span id="txt15_157c06d6" class="nokern" data-width="104.392250" style="top:396.614px;">отстранённо.</span></div><div style="width:0px;"><span id="txt16_157c06d6" class="nokern" data-width="633.482056" style="top:435.486px;">До шлюзового отсека мы дошли молча. О крутом повороте Кеми предупредить</span></div><div style="width:0px;"><span id="txt17_157c06d6" class="nokern" data-width="446.220795" style="top:459.394px;">не успел — я сам нащупал стену тростью и остановился.</span></div></div><div id="spr7_157c06d6" style="left:871.841px;top:159.241px;"><img id="img1_157c06d6" src="data:image/png;base64," width="27.704" height="40.034" alt="" style="left:-1.026px;"/></div><div id="spr8_157c06d6" style="left:787.113px;top:42.279px;"><div id="svg13_157c06d6" style="left:-3px;top:5.76px;"><svg width="381" height="121" viewBox="-3 -3 381 121"><g fill="none"><g transform="translate(3,3)"><path fill="#ffffff" d="M15.238,0 H353.555 C361.971,0 368.793,6.822 368.793,15.238 V93.271 C368.793,101.687 361.971,108.51 353.555,108.51 H15.238 C6.822,108.51 0,101.687 0,93.271 V15.238 C0,6.822 6.822,0 15.238,0 Z" fill-rule="evenodd"/></g><g transform="translate(3,3)"><path stroke="#7740d8" stroke-width="6" stroke-linecap="round" stroke-linejoin="round" d="M15.238,0 H353.555 C361.971,0 368.793,6.822 368.793,15.238 V93.271 C368.793,101.687 361.971,108.51 353.555,108.51 H15.238 C6.822,108.51 0,101.687 0,93.271 V15.238 C0,6.822 6.822,0 15.238,0 Z"/></g></g></svg></div><div id="svg14_157c06d6" style="left:3px;"><svg width="369" height="121" viewBox="0 0 369 121"><path fill="none" d="M0,0 h368.793 v120.27 h-368.793 Z"/></svg></div><div id="spr9_157c06d6" style="left:3px;"><div style="width:0px;"><span id="txt18_157c06d6" class="nokern" data-width="329.948486" style="left:19.397px;top:37.417px;">Подумайте, правильно ли поступил Кеми.</span></div><div style="width:0px;"><span id="txt19_157c06d6" class="nokern" data-width="268.631622" style="left:50.082px;top:65.272px;">Найдите ошибки в его поведении.</span></div></div></div></div></div>', '{"s":[]}');})();